// 2.7.101 | 2022-01-03 | raj  | STRY0116242 - Certification Fixes - Dot Walking to sys_id
// Script Continued Below
var Tasker_SaveTaskAsTemplate = Class.create();
Tasker_SaveTaskAsTemplate.prototype = {
    initialize: function() {
		gs.debug('x_153465_discovert.Tasker_SaveTaskAsTemplate - initialize');
		// STRY0110317 
		this.tdc = new TaskerDurationCalculator();
    },

	startSaveTemplate: function(recTemplate){
		try {
			// Create Top Tasker Definition Record
			var recTaskDef = new GlideRecord('x_153465_discovert_route_tasks');
			if(recTaskDef.get(recTemplate.parent_task_def)){
				var templateId = recTemplate.getUniqueValue();
				this.buildTaskTemplate(recTaskDef, templateId);
				recTemplate.setValue("u_save_tasks_completed", true);
				recTemplate.update();
			}
		} catch(e) {
			gs.error(e);
		}

	},

	buildTaskTemplate: function(recTaskDef, templateId) {
		try{
			gs.debug('x_153465_discovert.Tasker_SaveTaskAsTemplate - buildTaskTemplate start');

			var oTaskTemp = {};
			oTaskTemp.recTaskDef = recTaskDef;
			oTaskTemp.u_total_template_routes = 0;
			oTaskTemp.u_routes_loaded_count = 0;
			oTaskTemp.u_routes_order_count = 0;

			this.loadTaskTemplate(oTaskTemp);
			while (oTaskTemp.u_routes_loaded_count < oTaskTemp.u_total_template_routes) {
				// createTemplateTasksForOrderOnTask creates all of the template tasks for a single order on the task being saved
				this.createTemplateTasksForOrderOnTask(oTaskTemp, templateId);
			}
			gs.debug('x_153465_discovert.Tasker_SaveTaskAsTemplate - buildTaskTemplate end');
		} catch(e) {
			gs.error(e);
		}

	},

	loadTaskTemplate: function(oTaskTemp){		
		try{
			var taskInstanceQuery = new GlideAggregate('x_153465_discovert_route_task_instance');
			taskInstanceQuery.addQuery('parent',oTaskTemp.recTaskDef.original_tasker_inst);
			taskInstanceQuery.addAggregate('COUNT');
			taskInstanceQuery.query();
			if(taskInstanceQuery.next()){
				oTaskTemp.u_total_template_routes = taskInstanceQuery.getAggregate('COUNT');
			}
			gs.debug('x_153465_discovert.Tasker_SaveTaskAsTemplate - loadTaskTemplate - oTaskTemp.u_total_template_routes: ' + oTaskTemp.u_total_template_routes);
			gs.debug('x_153465_discovert.Tasker_SaveTaskAsTemplate - loadTaskTemplate end');
		} catch(e) {
			gs.error(e);
		}
	},	

	createTemplateTasksForOrderOnTask: function(oTaskTemp, templateId){
		try{
			gs.debug('x_153465_discovert.Tasker_SaveTaskAsTemplate - createTemplateTasksForOrderOnTask start');

			oTaskTemp.u_routes_order_count +=1;

			// we query to get the list of all Task instances in this "route order"
			// the loop below will process each Task instance in this route order
			// it will increment the total Task instances processed for each order
			var taskInstanceQuery = new GlideRecord('x_153465_discovert_route_task_instance');
			taskInstanceQuery.addQuery('parent',oTaskTemp.recTaskDef.original_tasker_inst).addCondition('order',oTaskTemp.u_routes_order_count);
			taskInstanceQuery.query();

			while (taskInstanceQuery.next()){
				var recTaskDef = new GlideRecord('x_153465_discovert_route_tasks');
				recTaskDef.initialize();
				// STRY0130087 - NOT .dot walking to sys_id as this is a JSON ojbect, not the glide record
				recTaskDef.parent = oTaskTemp.recTaskDef.sys_id;
				recTaskDef.tasker_process_definition = templateId;
				// STRY0130087 - changed to get unique value to avoide .dot walking to sys_id
				recTaskDef.original_tasker_inst = taskInstanceQuery.getUniqueValue();
				recTaskDef.insert();


				// buildTaskTemplate is called again to initiate the next level down the Template Tree
				var nextLevel =  new Tasker_SaveTaskAsTemplate();
				nextLevel.buildTaskTemplate(recTaskDef, templateId);

				// increment the total routes processed for each route in this order
				oTaskTemp.u_routes_loaded_count +=1;
			}
			gs.debug('x_153465_discovert.Tasker_SaveTaskAsTemplate - createTemplateTasksForOrderOnTask end');
		} catch(e) {
			gs.error(e);
		}

	},
    type: 'Tasker_SaveTaskAsTemplate'
};
